import{_ as o,H as i,f as s,i as a,b as r}from"./chunks/framework.D4aZISZY.js";const n="/SeaScan/assets/Rosenstiel%20HTML%20Map%20May%206.CRavFlMD.png",t="/SeaScan/assets/rectified_timelapse_small.BXMc-VOC.mp4",l="/SeaScan/assets/stitch_1.ZFZSrZnT.png",c="/SeaScan/assets/stitch_2.C3baFjn_.png",d="/SeaScan/assets/boats_timelapse.CATc1tr8.mp4",h="/SeaScan/assets/may_6_features.Bmu-M6or.jpg",m="/SeaScan/assets/demo_manual.BLm3eALG.png",S=JSON.parse('{"title":"SeaScan","description":"","frontmatter":{},"headers":[],"relativePath":"overview.md","filePath":"overview.md"}'),u={name:"overview.md"};function p(f,e,g,_,b,v){return i(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="seascan" tabindex="-1">SeaScan <a class="header-anchor" href="#seascan" aria-label="Permalink to &quot;SeaScan&quot;">​</a></h1><p>Constructing maps of flat regions should be a relatively simple task, but conventional approaches require complicated structure-from-motion pipelines intended for full 3D reconstruction. These methods often fail on scenes without distinguishable details, such as the ocean. We overcome this limitation through the use of target(s) and GPS data to stitch maps that are focused at a singular depth.</p><h3 id="map-of-waters-near-the-rosenstiel-school-using-the-mavic-3e" tabindex="-1">Map of Waters Near the Rosenstiel School using the MAVIC 3E <a class="header-anchor" href="#map-of-waters-near-the-rosenstiel-school-using-the-mavic-3e" aria-label="Permalink to &quot;Map of Waters Near the Rosenstiel School using the MAVIC 3E&quot;">​</a></h3><div style="display:flex;justify-content:space-around;"><img src="'+n+'" alt="drawing" width="300"><video controls src="'+t+'" width="300"></video></div><h2 id="products" tabindex="-1">Products <a class="header-anchor" href="#products" aria-label="Permalink to &quot;Products&quot;">​</a></h2><p>We present two methods of map generation depending on the amount of processing that should be done during or before viewing.</p><h3 id="folium-map" tabindex="-1">Folium Map <a class="header-anchor" href="#folium-map" aria-label="Permalink to &quot;Folium Map&quot;">​</a></h3><p>The simplest and quickest result is a map made with folium. It populates a map with a subset of downsampled images stacked on top of each other. While this is quick to generate, the tiles overlap, and your browser may switch between these tiles.</p>',8),r("iframe",{src:"https://npikielny.github.io/SeaScan/march_20_folium.html",frameborder:"0",width:"100%",height:"500px",allowfullscreen:""},null,-1),a('<p>This particular result uses fewer images, at a lower resolution, to work with Github.</p><h3 id="stitched-image" tabindex="-1">Stitched Image <a class="header-anchor" href="#stitched-image" aria-label="Permalink to &quot;Stitched Image&quot;">​</a></h3><p>Using our derived GPS transformation, we can stitch together high-quality images with limited noise from glint. This work is ongoing and the transforms of the corresponding geotiffs need correction.</p><div style="display:flex;justify-content:space-around;"><img src="'+l+'" alt="geotif stitching map 1–imagine a very windy drone path" width="300"><img src="'+c+'" alt="geotif stitching map 2-a map over some ocean and some land" width="300"></div><h3 id="timelapse-videos" tabindex="-1">Timelapse Videos <a class="header-anchor" href="#timelapse-videos" aria-label="Permalink to &quot;Timelapse Videos&quot;">​</a></h3><p>Lastly, we can collate data around a particular region to get an idea of the 3D shape, change over time, as well as a depiction of the accuracy of our GPS to image mapping. Notice in May 1, the image transform is slightly off, so objects on the sea surface appear to move.</p><div style="display:flex;justify-content:space-around;"><video controls src="'+t+'" width="300"></video><video controls src="'+d+'" width="300"></video></div><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><ol><li>Sea Surface Target</li></ol><p>Our method was designed to automatically detect mooring buoys for boats; however, you can also manually isolate a target, and in just a few images, the algorithm can achieve similar results. Thus, our method can be used on any type of target with minimal effort.</p><div style="display:flex;justify-content:space-around;"><div><h3>Automatic Feature Detection</h3><img src="'+h+'" alt="drawing" width="300"></div><div><h3>Manual Feature Annotation</h3><img src="'+m+'" alt="drawing" width="400"></div></div><ol start="2"><li>GPS Data</li></ol><p>Our method uses GPS data, as well as gimbal heading data, to align images. We designed with the Mavic 3E in mind, so the metadata should be found at <code>GimbalYawDegree</code> and <code>GimbalPitchDegree</code>. However, if these do not suit your data, you can edit the <code>gps.py</code> file.</p><ol start="3"><li>Camera Calibration (optional)</li></ol><p>In designing for the Mavic 3E, we also included parameters for its image undistortion. We included a notebook that leverages <a href="https://docs.opencv.org/3.4/dc/dbb/tutorial_py_calibration.html" target="_blank" rel="noreferrer">OpenCV checkerboard camera calibration</a>. This can be found in <code>Calibration.ipynb</code>.</p><blockquote><h1 id="you-can-find-our-code-here" tabindex="-1"><a href="https://github.com/Npikielny/SeaScan" target="_blank" rel="noreferrer">You can find our code here!</a> <a class="header-anchor" href="#you-can-find-our-code-here" aria-label="Permalink to &quot;[You can find our code here!](https://github.com/Npikielny/SeaScan)&quot;">​</a></h1></blockquote>',16)])])}const y=o(u,[["render",p]]);export{S as __pageData,y as default};
